# 文档清洗：把 PDF 文本切成结构化片段
import re

def clean_and_chunk(text, chunk_size=500):
    # 去除多余空白
    text = re.sub(r'\s+', ' ', text).strip()
    # 按段落切分
    paragraphs = text.split('。')
    chunks = []
    current = ''
    for p in paragraphs:
        if len(current) + len(p) < chunk_size:
            current += p + '。'
        else:
            if current: chunks.append(current)
            current = p + '。'
    if current: chunks.append(current)
    return chunks

