# RAG 结果校验清单
def validate_rag_answer(answer, sources):
    checks = {
        '有引用来源': any(s in answer for s in sources),
        '承认未知': '未提及' in answer or '不知道' in answer,
        '无编造': not any(w in answer for w in ['可能', '也许', '猜测']),
    }
    return {k: ('通过' if v else '不通过') for k, v in checks.items()}

